## Problem1(2.4.5.49)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "contextFiniteSolutionSets.pl",
  "contextForm.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
do {
  $c = non_zero_random(-9,9,1)+non_zero_random(-0.9,0.9,0.1);
  if ($c > 0) {
    $b = (random(int(sqrt(4*$c))+1,9,1) + random(0.1,0.9,0.1)) * list_random(-1,1);
  } else {
    $b = non_zero_random(-9,9,1)+non_zero_random(-0.9,0.9,0.1);
  }
} until (sqrt(($b**2-4*$c)*10) != int(sqrt(($b**2-4*$c)*10)));
Context()->noreduce('(-x)-y','(-x)+y');
$f = Formula("x^2+$b x+$c")->reduce;
$disc = $b**2-4*$c;
$B = $b/2;
$negb = -$b;
$bsquared = ($b)**2;
$discriminant = ($b)**2 - 4*$c;
$sqrtdisc = Real(sqrt($discriminant));
Context("FiniteSolutionSets");
Context()->flags->remove("NumberCheck");
Context()->flags->set(useBizarro=>0);
$r = Real(-$B - 1/2*sqrt($disc));
$s = Real(-$B + 1/2*sqrt($disc));
$solutions = Formula("{$r,$s}");

############################################################
# Body
############################################################

BEGIN_PGML
Use the quadratic formula to solve the equation.

[`[$f]=0`]

[@KeyboardInstructions('If you need to enter a square root like [`\sqrt{17}\text{,}`] type [|sqrt(17)|]*. If there is no real solution, enter [|no real solution|]*.')@]**

[_]{$solutions}{40}

END_PGML

############################################################
# Solution
############################################################

BEGIN_PGML_SOLUTION
To use the quadratic formula, we identify [`a=1\text{,}`] [`b=[$b]\text{,}`] and [`c=[$c]\text{.}`]

[```\newcommand{\amp}{&}
\begin{aligned}
x\amp=\frac{-b\pm\sqrt{b^2-4ac}}{2a}\\
\amp=\frac{[$negb]\pm\sqrt{[$bsquared]-4(1)([$c])}}{2}\\
\amp=\frac{[$negb]\pm\sqrt{[$discriminant]}}{2}\\
\amp\approx\frac{[$negb]\pm[$sqrtdisc]}{2}\\
x\amp\approx\frac{[$negb]-[$sqrtdisc]}{2}\quad\text{or}\quad x\approx\frac{[$negb]+[$sqrtdisc]}{2}\\
x\amp\approx[$r]\quad\text{or}\quad x\approx[$s]
\end{aligned}
```]

The solution set is approximately [`[$solutions]\text{.}`] Note that since we started with decimal coefficients, we felt it was acceptible to round the solutions to decimal approximations rather than keep to the exact solutions.

END_PGML_SOLUTION

############################################################
# End Problem
############################################################

ENDDOCUMENT();
